1	const PROCESSING_FEE = 5;
2	const BLOCK_SIZE = 3;
3	const BLOCK_PRICE = 60;
4	
5	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	
14	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
15	
16	type Item = { type: string; material: string; enchantment: number; cursed: boolean };
17	
18	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
19	
20	const componentBlockBaseFor = (count: number, type: string): number =>
21	  count === BLOCK_SIZE
22	    ? BLOCK_PRICE
23	    : count * BASE_PREMIUM_BY_ITEM_TYPE[type];
24	
25	const componentsBaseFor = (items: Item[]): number => {
26	  const countsByType = new Map<string, number>();
27	  for (const item of items) {
28	    countsByType.set(item.type, (countsByType.get(item.type) ?? 0) + 1);
29	  }
30	  let total = 0;
31	  for (const [type, count] of countsByType) {
32	    total += componentBlockBaseFor(count, type);
33	  }
34	  return total;
35	};
36	
37	const CURSE_SURCHARGE_RATE = 0.5;
38	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
39	const HIGH_ENCHANTMENT_THRESHOLD = 5;
40	
41	const surchargesFor = (item: Item, base: number): number => {
42	  const curse = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
43	  const highEnchantment = item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
44	  return curse + highEnchantment;
45	};
46	
47	const nonComponentBaseFor = (items: Item[]): number =>
48	  items.reduce((sum, item) => {
49	    const base = BASE_PREMIUM_BY_ITEM_TYPE[item.type];
50	    return sum + base + surchargesFor(item, base);
51	  }, 0);
52	
53	export function quote(input: { yearsWithMHPCO: number; items: Item[] }): number {
54	  const components = input.items.filter(isComponent);
55	  const nonComponents = input.items.filter((item) => !isComponent(item));
56	  return nonComponentBaseFor(nonComponents) + componentsBaseFor(components) + PROCESSING_FEE;
57	}
